import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

/**
 * Repository for user data access.
 *
 * <p><b>Thread safety:</b> This class is thread-safe. All methods
 * may be called concurrently from multiple threads.
 */
public class UserRepository {

    /**
     * Finds a user by their unique ID.
     *
     * @param userId the user ID; must be positive
     * @return the user, or {@code null} if not found
     * @throws IllegalArgumentException if {@code userId} is not positive
     */
    @Nullable
    public User findById(@NotNull Long userId) {
        if (userId <= 0) throw new IllegalArgumentException("userId must be positive");
        return db.findById(userId).orElse(null);
    }

    /**
     * Saves a user. If the user has an ID, it is updated; otherwise inserted.
     *
     * @param user the user to save; must not be null, name must not be blank
     * @return the saved user with its generated ID populated
     */
    @NotNull
    public User save(@NotNull User user) { ... }
}

